      <line x1="40" y1="300" x2="660" y2="300" stroke="#3f3f46" stroke-width="1.5"/>
      <rect x="120" y="120" width="120" height="180" rx="6" fill="#a1a1aa"/>
      <text x="180" y="105" fill="#e4e4e7" font-size="15" font-weight="700" text-anchor="middle">$344.2M</text>
